"use strict";parserFactory.register("marxists.org",()=>new MarxistsCNParser);class MarxistsCNParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=[],r=e.querySelector("table[border='0']").querySelectorAll("a");for(let e of r)e.href&&e.href.endsWith(".htm")&&t.push({sourceUrl:e.href,title:e.textContent});return t}findContent(e){return e.querySelector("body")}extractTitleImpl(e){return e.querySelector("title0")}extractLanguage(){return"cn"}extractAuthor(e){let t=e.querySelector("author");return null===t?"":t.textContent}findChapterTitle(e){return e.querySelector("title")}async fetchChapter(e){let t={makeTextDecoder:()=>new TextDecoder("gbk")};return(await HttpClient.wrapFetch(e,t)).responseXML}}